#include <bits/stdc++.h>
#define ull unsigned long long
#define mk(x,y) make_pair(x,y)
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb(x) push_back(x)
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh(x) while(x)
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e5+5;
int n,W,c,w,m,f[MAXN];
int main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
    n=read();W=read();
    FOR(i,1,n)
    {
        w=read();
        c=read();
        m=read();
        if(m * c >= W)
        {
            FOR(i,c,W)
            {
                f[i] = max(f[i], f[i-c] + w);
            }
        }
        else
        {
            int k = 1;
            while(k < m)
            {
                ROF(i,W,c*k)
                {
                    f[i] = max(f[i], f[i-c*k] + w*k);
                }
                m -= k;
                k <<= 1;
            }
            ROF(i,W,c*m) 
            {
                f[i] = max(f[i], f[i-c*m] + w*m);
            }
        }
    }
    writeln(f[W]);
    return false;
}
